-- Baseline catalog seed for Minh Giang Pharmacy.
-- Keep only stable master data. Product/article data must be generated from the cleaned crawl pipeline.

USE mg_catalog;
SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

TRUNCATE TABLE product_images;
TRUNCATE TABLE product_specifications;
TRUNCATE TABLE product_units;
TRUNCATE TABLE stock_reservations;
TRUNCATE TABLE stock_movements;
TRUNCATE TABLE audit_items;
TRUNCATE TABLE inventory_audits;
TRUNCATE TABLE batch_items;
TRUNCATE TABLE batches;
TRUNCATE TABLE catalog_audit_logs;
TRUNCATE TABLE catalog_idempotency_keys;
TRUNCATE TABLE product_recalls;
TRUNCATE TABLE products;
TRUNCATE TABLE catalog_gift_campaigns;
TRUNCATE TABLE catalog_vouchers;
TRUNCATE TABLE locations;
TRUNCATE TABLE suppliers;
TRUNCATE TABLE brands;
TRUNCATE TABLE categories;






 JSON_ARRAY(
   JSON_OBJECT('code','member','name','Thành viên','min_spend',0,'discount_pct',0),
   JSON_OBJECT('code','silver','name','Bạc','min_spend',5000000,'discount_pct',2),
   JSON_OBJECT('code','gold','name','Vàng','min_spend',20000000,'discount_pct',5),
   JSON_OBJECT('code','vip','name','VIP','min_spend',50000000,'discount_pct',10)
 ),
 JSON_OBJECT('points_per_vnd',0.0001,'min_redeem_points',100),
 JSON_ARRAY('pos','web')
)
ON DUPLICATE KEY UPDATE tiers = VALUES(tiers), redemption = VALUES(redemption), channels = VALUES(channels);

ON DUPLICATE KEY UPDATE
  max_delivery_radius_km = VALUES(max_delivery_radius_km),
  base_shipping_fee = VALUES(base_shipping_fee),
  free_shipping_threshold = VALUES(free_shipping_threshold),
  is_enabled = VALUES(is_enabled);

ON DUPLICATE KEY UPDATE
  label = VALUES(label), start_time = VALUES(start_time), end_time = VALUES(end_time),
  slot_type = VALUES(slot_type), is_active = VALUES(is_active), sort_order = VALUES(sort_order);

SET FOREIGN_KEY_CHECKS = 1;
